import React, { useEffect, useState, useCallback, useMemo } from 'react';
import api from '../api/axiosConfig';
import {
  Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, PieChart, FileText, Zap,
} from 'lucide-react';
import toast from 'react-hot-toast';

const formatDate = (dateStr) => {
  if (!dateStr) return '—';
  try {
    return new Date(dateStr).toLocaleDateString('en-GB', {
      day: '2-digit', month: 'short', year: 'numeric',
    });
  } catch {
    return 'Invalid date';
  }
};

const parseHoldings = (raw) => {
  if (!raw) return [];

  // Fast path: already clean array of strings
  if (Array.isArray(raw) && raw.every((h) => typeof h === 'string')) {
    return raw;
  }

  let value = raw;

  // Handle stringified cases (most common source of issues)
  if (typeof value === 'string') {
    try {
      value = JSON.parse(value);
      if (typeof value === 'string') {
        value = JSON.parse(value); // double stringified
      }
    } catch {
      return [];
    }
  }

  if (Array.isArray(value)) {
    return value.map((h) => {
      if (typeof h === 'string') return h;
      return h?.symbol || h?.ticker || h?.name || String(h ?? '');
    });
  }

  // Nested object fallback
  if (value && typeof value === 'object') {
    for (const key of ['holdings', 'assets', 'positions', 'items']) {
      if (Array.isArray(value[key])) {
        return parseHoldings(value[key]);
      }
    }
  }

  return [];
};

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const fetchHistory = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/portfolio/history');
      setHistory(Array.isArray(data) ? data : []);
    } catch (err) {
      toast.error('Failed to load strategies');
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  const handleDelete = useCallback(async (id) => {
    if (!window.confirm('Delete this strategy permanently?')) return;
    const toastId = toast.loading('Deleting...');
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory((prev) => prev.filter((it) => it.id !== id));
      toast.success('Deleted', { id: toastId });
    } catch {
      toast.error('Delete failed', { id: toastId });
    }
  }, []);

  const handleDownload = useCallback(async (item) => {
    const toastId = toast.loading('Exporting PDF...');
    try {
      const { data } = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = URL.createObjectURL(new Blob([data], { type: 'application/pdf' }));
      const link = document.createElement('a');
      link.href = url;
      link.download = `Strategy_${item.id || 'unnamed'}.pdf`;
      link.click();
      URL.revokeObjectURL(url);
      toast.success('Downloaded', { id: toastId });
    } catch {
      toast.error('Export failed', { id: toastId });
    }
  }, []);

  const holdingsById = useMemo(() => {
    const map = {};
    history.forEach((item) => {
      map[item.id] = parseHoldings(item.holdings);
    });
    return map;
  }, [history]);

  if (loading) {
    return (
      <div style={styles.center}>
        <div className="loading-pulse">Loading vault...</div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h2 style={styles.title}>
          <Archive size={20} /> Strategy Vault
        </h2>
        <span style={styles.badge}>
          {history.length} {history.length === 1 ? 'item' : 'items'}
        </span>
      </header>

      {history.length === 0 ? (
        <div style={styles.emptyState}>
          No saved strategies yet.
        </div>
      ) : (
        <div style={styles.grid}>
          {history.map((item) => {
            const holdings = holdingsById[item.id] || [];
            return (
              <div key={item.id} style={styles.card}>
                <div style={styles.cardMain}>
                  <div style={styles.meta}>
                    <span style={styles.date}>
                      <Calendar size={13} /> {formatDate(item.created_at)}
                    </span>
                    <span style={styles.risk}>
                      <ShieldCheck size={13} /> {Number(item.risk_score ?? 0).toFixed(1)}
                    </span>
                  </div>

                  <h3 style={styles.goal}>
                    {item.goal?.trim() || 'Unnamed Strategy'}
                  </h3>

                  <div style={styles.holdingsSection}>
                    <div style={styles.sectionHeader}>
                      <PieChart size={12} /> Holdings
                    </div>
                    <div style={styles.chips}>
                      {holdings.length > 0 ? (
                        holdings.map((t, i) => (
                          <span key={i} style={styles.chip}>
                            {t}
                          </span>
                        ))
                      ) : (
                        <span style={styles.noData}>—</span>
                      )}
                    </div>
                  </div>
                </div>

                <div style={styles.actions}>
                  <button
                    style={styles.btn}
                    onClick={() => setSelectedItem(item)}
                    title="View details"
                    aria-label="View strategy details"
                  >
                    <Eye size={18} />
                  </button>
                  <button
                    style={styles.btn}
                    onClick={() => handleDownload(item)}
                    title="Export PDF"
                    aria-label="Download PDF"
                  >
                    <Download size={18} />
                  </button>
                  <button
                    style={{ ...styles.btn, color: '#ef4444' }}
                    onClick={() => handleDelete(item.id)}
                    title="Delete"
                    aria-label="Delete strategy"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {selectedItem && (
        <div style={styles.modalOverlay} onClick={() => setSelectedItem(null)}>
          <div style={styles.modal} onClick={(e) => e.stopPropagation()}>
            <div style={styles.modalHeader}>
              <h4 style={styles.modalTitle}>
                Strategy {selectedItem.id ? `#${selectedItem.id}` : ''}
              </h4>
              <button
                style={styles.close}
                onClick={() => setSelectedItem(null)}
                aria-label="Close"
              >
                <X size={22} />
              </button>
            </div>

            <div style={styles.modalContent}>
              <section style={styles.section}>
                <h5 style={styles.sectionTitle}>
                  <FileText size={14} /> Summary
                </h5>
                <p style={styles.text}>
                  {selectedItem.summary || 'No summary available.'}
                </p>
              </section>

              <hr style={styles.divider} />

              <section style={styles.section}>
                <h5 style={styles.sectionTitle}>
                  <Zap size={14} /> Rationale
                </h5>
                <div style={styles.rationale}>
                  {selectedItem.rationale ? (
                    selectedItem.rationale.split(/\n+/).map((line, i) => (
                      <p key={i} style={styles.rationaleLine}>{line.trim()}</p>
                    ))
                  ) : (
                    <p style={{ color: '#888' }}>No rationale provided.</p>
                  )}
                </div>
              </section>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

